# Training job that reads and verifies dataset governance metadata
import hashlib, json
from pathlib import Path

class GovernedTrainingJob:
    def __init__(self, registry_client):
        self.registry = registry_client

    def verify_dataset_before_training(self, dataset_id: str, version: str, local_path: str) -> bool:
        """Verify dataset integrity and governance clearance before starting training."""
        record = self.registry.get(dataset_id, version)

        # Check governance clearance
        if record["pii_scan_status"] != "passed":
            raise ValueError(f"Dataset {dataset_id}@{version} has not passed PII scan")
        if record["bias_review_status"] != "approved":
            raise ValueError(f"Dataset {dataset_id}@{version} has not passed bias review")

        # Verify content hash
        p = Path(local_path)
        file_hashes = {}
        for f in sorted(p.rglob("*")):
            if f.is_file():
                sha256 = hashlib.sha256(f.read_bytes()).hexdigest()
                file_hashes[str(f.relative_to(p))] = sha256

        computed_hash = hashlib.sha256(
            json.dumps(file_hashes, sort_keys=True).encode()
        ).hexdigest()

        if computed_hash != record["manifest_hash"]:
            raise ValueError(
                f"Dataset content hash mismatch. "
                f"Expected {record['manifest_hash'][:16]}..., "
                f"got {computed_hash[:16]}..."
            )

        print(f"Dataset {dataset_id}@{version} verified: governance cleared, content hash matches")
        return True
